# ML Survival Guide: knowledge base system
guide_entries = {
    "data_leakage": {
        "symptom": "Model achieves 99% accuracy on test set but 60% in production",
        "checklist": [
            "Check for temporal leakage (future data leaking into training)",
            "Check for feature leakage (target-correlated features not available at inference)",
            "Check for group leakage (same entity in train and test)",
        ],
        "fix": "Use group-k-fold cross-validation with time-based splits. Validate feature availability at inference time.",
    },
    "metric_selection": {
        "framework": {
            "balanced_classes": "Accuracy or F1",
            "imbalanced": "Precision-Recall AUC or F2",
            "ranking": "NDCG@k or MRR",
            "regression": "MAE (interpretable) or MSE (outlier-sensitive)",
            "cost-sensitive": "Custom loss + weighted metrics",
        },
        "advice": "Always start with 2-3 metrics: one primary (business-aligned), one diagnostic (helps debugging), one guardrail (must not degrade).",
    },
    "experiment_design": {
        "template": {
            "hypothesis": "Adding user embeddings will improve CTR by 5%",
            "baseline": "Current production model (no embeddings)",
            "treatment": "Same model + user embeddings",
            "metrics": ["CTR (primary)", "session_duration (guardrail)", "embedding_norm (diagnostic)"],
            "sample_size": "CUPED power analysis: 100K users per arm, 2 weeks",
        }
    }
}

# Function: junior engineer can query the guide
from difflib import get_close_matches

def query_survival_guide(question):
    """Find the most relevant guide entry for a question"""
    topics = list(guide_entries.keys())
    matches = get_close_matches(question.lower(), topics, n=1, cutoff=0.3)

    if matches:
        entry = guide_entries[matches[0]]
        return entry
    else:
        return {
            "message": "Not in guide yet. Bring this to office hours! "
                       "We'll add it to the guide after."
        }

# Mentor capacity: 1 (I answer) vs 25 (guide answers before I even see it)
print(f"Mentorship capacity: 25 engineers served via guide + rotation")
print(f"Guide entries after 3 months: {len(guide_entries)}")
